    if not os.path.exists(input_file):
        raise ValueError("Input file does not exist")

    # Check if output file is a valid path
    if not os.path.isabs(output_file):
        raise ValueError("Output file is not a valid path")

    # Check if conversion format is supported
    if conversion_format not in ["pdf", "docx"]:
        raise ValueError("Conversion format is not supported")

    # Create command-line arguments for LibreOffice
    args = [
        "libreoffice",
        "--headless",
        "--convert-to", conversion_format,
        "--outdir", os.path.dirname(output_file),
        input_file
    ]

    # Run LibreOffice with the created arguments
    process = Popen(args, stdout=PIPE, stderr=PIPE)
    output, error = process.communicate()

    # Check if conversion was successful
    if process.returncode != 0:
        raise ValueError("Conversion failed")

    # Return the converted file path
    return output_file